import express, { type Request, type Response, type NextFunction } from 'express';
import cors from 'cors';
import type { ServerConfig, AppDependencies, ErrorHandlerContext } from '../types';
import { todoRoutes } from './routes/todos';

const app = express();
const PORT = process.env.PORT ? parseInt(process.env.PORT, 10) : 3000;

const serverConfig: ServerConfig = {
  port: PORT,
  host: process.env.HOST || '0.0.0.0',
  corsOrigins: process.env.CORS_ORIGINS
    ? process.env.CORS_ORIGINS.split(',')
    : ['http://localhost:5173', 'http://localhost:3000'],
};

// ---------------------------------------------------------------------------
// 依赖注入：简单内存数据库
// ---------------------------------------------------------------------------
interface Todo {
  id: string;
  title: string;
  completed: boolean;
  createdAt: string;
  updatedAt: string;
}

class Database {
  private todos: Map<string, Todo> = new Map();

  getTodos(): Todo[] {
    return Array.from(this.todos.values());
  }

  getTodo(id: string): Todo | undefined {
    return this.todos.get(id);
  }

  createTodo(todo: Todo): Todo {
    this.todos.set(todo.id, todo);
    return todo;
  }

  updateTodo(id: string, updates: Partial<Todo>): Todo | undefined {
    const existing = this.todos.get(id);
    if (!existing) return undefined;
    const updated = { ...existing, ...updates, updatedAt: new Date().toISOString() };
    this.todos.set(id, updated);
    return updated;
  }

  deleteTodo(id: string): boolean {
    return this.todos.delete(id);
  }

  clear(): void {
    this.todos.clear();
  }

  get size(): number {
    return this.todos.size;
  }
}

const db = new Database();
const dependencies: AppDependencies = { db };

// ---------------------------------------------------------------------------
// 中间件
// ---------------------------------------------------------------------------
app.use(
  cors({
    origin: serverConfig.corsOrigins,
    credentials: true,
  })
);
app.use(express.json());

// ---------------------------------------------------------------------------
// 路由 — /api/v1/todos
// ---------------------------------------------------------------------------
app.use('/api/v1/todos', todoRoutes(dependencies));

// ---------------------------------------------------------------------------
// 全局错误处理中间件
// ---------------------------------------------------------------------------
app.use((err: ErrorHandlerContext, _req: Request, res: Response, _next: NextFunction) => {
  const statusCode = err.statusCode || 500;
  const message = err.message || 'Internal Server Error';
  console.error(`[Error] ${statusCode} - ${message}`);
  res.status(statusCode).json({
    success: false,
    error: {
      code: err.code || 'UNKNOWN_ERROR',
      message,
    },
  });
});

// ---------------------------------------------------------------------------
// 404 兜底
// ---------------------------------------------------------------------------
app.use((_req: Request, res: Response) => {
  res.status(404).json({
    success: false,
    error: {
      code: 'NOT_FOUND',
      message: `Route ${_req.method} ${_req.originalUrl} not found`,
    },
  });
});

// ---------------------------------------------------------------------------
// 启动服务
// ---------------------------------------------------------------------------
async function startServer(): Promise<void> {
  try {
    // 初始化数据库（此处可扩展为连接真实数据库）
    console.log('Database initialized successfully');

    app.listen(serverConfig.port, serverConfig.host, () => {
      console.log(`Server running at http://${serverConfig.host}:${serverConfig.port}`);
      console.log(`CORS origins: ${serverConfig.corsOrigins.join(', ')}`);
    });
  } catch (error) {
    console.error('Failed to start server:', error);
    process.exit(1);
  }
}

startServer();

