import { Router, Request, Response, NextFunction } from 'express';
import type { TodoQueryParams, TodoRouteHandlers, TodoRouterConfig, AsyncHandler } from '../types';
import { Database } from '../db';

/**
 * 创建待办事项路由处理函数
 */
function createTodoHandlers(db: Database): TodoRouteHandlers {
  /**
   * 获取所有待办事项
   * GET /todos
   * 支持分页、筛选、搜索
   */
  const getAllTodos: AsyncHandler = async (req: Request, res: Response) => {
    const {
      completed,
      search,
      page = '1',
      limit = '10',
    } = req.query as TodoQueryParams;

    const pageNum = Math.max(1, parseInt(page, 10) || 1);
    const limitNum = Math.min(100, Math.max(1, parseInt(limit, 10) || 10));
    const offset = (pageNum - 1) * limitNum;

    let baseQuery = 'SELECT * FROM todos WHERE 1=1';
    const queryParams: any[] = [];
    let countQuery = 'SELECT COUNT(*) as total FROM todos WHERE 1=1';
    const countParams: any[] = [];

    if (completed !== undefined) {
      const isCompleted = completed === 'true' ? 1 : 0;
      baseQuery += ' AND completed = ?';
      queryParams.push(isCompleted);
      countQuery += ' AND completed = ?';
      countParams.push(isCompleted);
    }

    if (search && search.trim()) {
      const searchTerm = `%${search.trim()}%`;
      baseQuery += ' AND (title LIKE ? OR description LIKE ?)';
      queryParams.push(searchTerm, searchTerm);
      countQuery += ' AND (title LIKE ? OR description LIKE ?)';
      countParams.push(searchTerm, searchTerm);
    }

    baseQuery += ' ORDER BY created_at DESC LIMIT ? OFFSET ?';
    queryParams.push(limitNum, offset);

    const [todos] = await db.query(baseQuery, queryParams);
    const [countResult] = await db.query(countQuery, countParams);
    const total = countResult[0]?.total || 0;

    res.status(200).json({
      success: true,
      data: todos,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total,
        totalPages: Math.ceil(total / limitNum),
      },
    });
  };

  /**
   * 获取单个待办事项
   * GET /todos/:id
   */
  const getTodoById: AsyncHandler = async (req: Request, res: Response) => {
    const { id } = req.params;
    const [todos] = await db.query('SELECT * FROM todos WHERE id = ?', [id]);

    if (!todos || todos.length === 0) {
      res.status(404).json({
        success: false,
        error: {
          message: '待办事项不存在',
          code: 'NOT_FOUND',
        },
      });
      return;
    }

    res.status(200).json({
      success: true,
      data: todos[0],
    });
  };

  /**
   * 创建待办事项
   * POST /todos
   */
  const createTodo: AsyncHandler = async (req: Request, res: Response) => {
    const { title, description = '' } = req.body;

    if (!title || typeof title !== 'string' || title.trim().length === 0) {
      res.status(400).json({
        success: false,
        error: {
          message: '标题不能为空',
          code: 'VALIDATION_ERROR',
          details: { field: 'title' },
        },
      });
      return;
    }

    const trimmedTitle = title.trim();
    const trimmedDescription = description.trim();

    const result = await db.query(
      'INSERT INTO todos (title, description, completed, created_at, updated_at) VALUES (?, ?, 0, NOW(), NOW())',
      [trimmedTitle, trimmedDescription]
    );

    const insertId = result.insertId;
    const [newTodos] = await db.query('SELECT * FROM todos WHERE id = ?', [insertId]);

    res.status(201).json({
      success: true,
      data: newTodos[0],
    });
  };

  /**
   * 更新待办事项
   * PUT /todos/:id
   */
  const updateTodo: AsyncHandler = async (req: Request, res: Response) => {
    const { id } = req.params;
    const { title, description, completed } = req.body;

    if (title !== undefined && (typeof title !== 'string' || title.trim().length === 0)) {
      res.status(400).json({
        success: false,
        error: {
          message: '标题不能为空',
          code: 'VALIDATION_ERROR',
          details: { field: 'title' },
        },
      });
      return;
    }

    const [existing] = await db.query('SELECT * FROM todos WHERE id = ?', [id]);
    if (!existing || existing.length === 0) {
      res.status(404).json({
        success: false,
        error: {
          message: '待办事项不存在',
          code: 'NOT_FOUND',
        },
      });
      return;
    }

    const current = existing[0];
    const updatedTitle = title !== undefined ? title.trim() : current.title;
    const updatedDescription = description !== undefined ? description.trim() : current.description;
    const updatedCompleted = completed !== undefined ? (completed ? 1 : 0) : current.completed;

    await db.query(
      'UPDATE todos SET title = ?, description = ?, completed = ?, updated_at = NOW() WHERE id = ?',
      [updatedTitle, updatedDescription, updatedCompleted, id]
    );

    const [updatedTodos] = await db.query('SELECT * FROM todos WHERE id = ?', [id]);

    res.status(200).json({
      success: true,
      data: updatedTodos[0],
    });
  };

  /**
   * 删除待办事项
   * DELETE /todos/:id
   */
  const deleteTodo: AsyncHandler = async (req: Request, res: Response) => {
    const { id } = req.params;

    const [existing] = await db.query('SELECT * FROM todos WHERE id = ?', [id]);
    if (!existing || existing.length === 0) {
      res.status(404).json({
        success: false,
        error: {
          message: '待办事项不存在',
          code: 'NOT_FOUND',
        },
      });
      return;
    }

    await db.query('DELETE FROM todos WHERE id = ?', [id]);

    res.status(200).json({
      success: true,
      message: '待办事项已删除',
    });
  };

  /**
   * 切换完成状态
   * PATCH /todos/:id/toggle
   */
  const toggleTodo: AsyncHandler = async (req: Request, res: Response) => {
    const { id } = req.params;

    const [existing] = await db.query('SELECT * FROM todos WHERE id = ?', [id]);
    if (!existing || existing.length === 0) {
      res.status(404).json({
        success: false,
        error: {
          message: '待办事项不存在',
          code: 'NOT_FOUND',
        },
      });
      return;
    }

    const currentCompleted = existing[0].completed;
    const newCompleted = currentCompleted ? 0 : 1;

    await db.query('UPDATE todos SET completed = ?, updated_at = NOW() WHERE id = ?', [
      newCompleted,
      id,
    ]);

    const [updatedTodos] = await db.query('SELECT * FROM todos WHERE id = ?', [id]);

    res.status(200).json({
      success: true,
      data: updatedTodos[0],
    });
  };

  return {
    getAllTodos,
    getTodoById,
    createTodo,
    updateTodo,
    deleteTodo,
    toggleTodo,
  };
}

/**
 * 创建待办事项路由
 */
export function createTodoRouter(config: TodoRouterConfig): Router {
  const router = Router();
  const handlers = createTodoHandlers(config.db);

  // GET /todos - 获取所有待办事项
  router.get('/', handlers.getAllTodos);

  // GET /todos/:id - 获取单个待办事项
  router.get('/:id', handlers.getTodoById);

  // POST /todos - 创建待办事项
  router.post('/', handlers.createTodo);

  // PUT /todos/:id - 更新待办事项
  router.put('/:id', handlers.updateTodo);

  // DELETE /todos/:id - 删除待办事项
  router.delete('/:id', handlers.deleteTodo);

  // PATCH /todos/:id/toggle - 切换完成状态
  router.patch('/:id/toggle', handlers.toggleTodo);

  return router;
}

